mapper.select:
SELECT sfid, mertermno as merTermNo, affiliationstorenamekanji as affiliationStoreNameKanji, appcompanyid as appCompanyId, affiliationstorenamekana as affiliationStoreNameKana, merchantinfo_radename as merchantInfoRadeName, merchantinfo_contactname as merchantInfoContactName FROM account acc
WHERE acc.appcompany=#{appCompanyId,jdbcType=VARCHAR}
ORDER BY merTermNo ASC
